{"content":"/**
 * metrics.js
 * System metrics collection module using systeminformation
 * Provides normalized CPU and Memory data for the dashboard
 */

const si = require('systeminformation');

/**
 * Format bytes to human-readable string (GB, MB, etc.)
 */
function formatBytes(bytes, decimals = 2) {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

/**
 * Collect all CPU metrics
 * Returns: { usage, cores[], frequency, loadAverage }
 */
async function getCpuMetrics() {
    try {
        const [currentLoad, cpuSpeed, load] = await Promise.all([
            si.currentLoad(),
            si.cpuCurrentSpeed(),
            si.load()
        ]);

        // Per-core usage percentages
        const cores = currentLoad.cpus.map(core => parseFloat(core.load.toFixed(1)));

        // Overall CPU usage
        const usage = parseFloat(currentLoad.currentload.toFixed(1));

        // CPU frequency (average in GHz)
        const frequency = cpuSpeed.avg ? parseFloat(cpuSpeed.avg.toFixed(2)) : 0;

        // Load average (1min, 5min, 15min) - available on Unix-like systems
        // On Windows, systeminformation may return different structure
        let loadAverage = [0, 0, 0];
        if (load && load.currentload !== undefined) {
            loadAverage = [
                parseFloat(load.currentload.toFixed(2)),
                parseFloat((load.avgload || load.currentload).toFixed(2)),
                parseFloat((load.avgload || load.currentload).toFixed(2))
            ];
        }

        return {
            usage,
            cores,
            frequency,
            loadAverage
        };
    } catch (error) {
        console.error('Error collecting CPU metrics:', error);
        return {
            usage: 0,
            cores: [],
            frequency: 0,
            loadAverage: [0, 0, 0]
        };
    }
}

/**
 * Collect all Memory metrics
 * Returns: { total, used, free, available, active, buffers, cached, swapTotal, swapUsed, swapFree }
 */
async function getMemoryMetrics() {
    try {
        const mem = await si.mem();

        return {
            total: mem.total || 0,
            used: mem.used || 0,
            free: mem.free || 0,
            available: mem.available || 0,
            active: mem.active || 0,
            buffers: mem.buffers || 0,
            cached: mem.cached || 0,
            swapTotal: mem.swaptotal || 0,
            swapUsed: mem.swapused || 0,
            swapFree: mem.swapfree || 0
        };
    } catch (error) {
        console.error('Error collecting memory metrics:', error);
        return {
            total: 0,
            used: 0,
            free: 0,
            available: 0,
            active: 0,
            buffers: 0,
            cached: 0,
            swapTotal: 0,
            swapUsed: 0,
            swapFree: 0
        };
    }
}

/**
 * Collect all system metrics in one call
 * Returns unified payload for WebSocket broadcast
 */
async function getAllMetrics() {
    const [cpu, memory] = await Promise.all([
        getCpuMetrics(),
        getMemoryMetrics()
    ]);

    return {
        timestamp: Date.now(),
        cpu,
        memory
    };
}

module.exports = {
    getCpuMetrics,
    getMemoryMetrics,
    getAllMetrics,
    formatBytes
};
