// ==================== CONFIGURATION ====================
const WS_URL = `ws://${window.location.host}`;
const MAX_HISTORY_POINTS = 60; // 60 seconds of history
const UPDATE_INTERVAL = 1000;

// ==================== STATE ====================
let ws = null;
let reconnectAttempts = 0;
const maxReconnectAttempts = 10;
let isConnected = false;

// Chart instances
let cpuChart = null;
let memoryChart = null;

// History data arrays
const cpuHistory = {
    labels: [],
    overall: [],
    cores: [] // Array of arrays, one per core
};

const memoryHistory = {
    labels: [],
    used: [],
    available: []
};

// ==================== UTILITY FUNCTIONS ====================

/**
 * Format bytes to human-readable string
 */
function formatBytes(bytes, decimals = 2) {
    if (bytes === 0 || bytes === undefined || bytes === null) return '0 B';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

/**
 * Format timestamp to HH:MM:SS
 */
function formatTime(timestamp) {
    const date = new Date(timestamp);
    return date.toTimeString().split(' ')[0];
}

/**
 * Get color based on percentage (green → yellow → red)
 */
function getColorForPercentage(pct) {
    if (pct < 50) return '#00d4aa';
    if (pct < 80) return '#ffd93d';
    return '#ff6b6b';
}

// ==================== CHART INITIALIZATION ====================

/**
 * Initialize CPU History Chart
 */
function initCpuChart() {
    const ctx = document.getElementById('cpuChart').getContext('2d');

    cpuChart = new Chart(ctx, {
        type: 'line',
        data: {
            labels: [],
            datasets: [{
                label: 'Overall CPU %',
                data: [],
                borderColor: '#00d4aa',
                backgroundColor: 'rgba(0, 212, 170, 0.1)',
                borderWidth: 2,
                fill: true,
                tension: 0.4,
                pointRadius: 0,
                pointHoverRadius: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: false,
            plugins: {
                legend: {
                    display: true,
                    labels: { color: '#a0a0b0' }
                }
            },
            scales: {
                x: {
                    display: false
                },
                y: {
                    min: 0,
                    max: 100,
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: '#707080',
                        callback: function(value) {
                            return value + '%';
                        }
                    }
                }
            },
            interaction: {
                intersect: false,
                mode: 'index'
            }
        }
    });
}

/**
 * Initialize Memory History Chart
 */
function initMemoryChart() {
    const ctx = document.getElementById('memoryChart').getContext('2d');

    memoryChart = new Chart(ctx, {
        type: 'line',
        data: {
            labels: [],
            datasets: [{
                label: 'Used',
                data: [],
                borderColor: '#ff6b6b',
                backgroundColor: 'rgba(255, 107, 107, 0.1)',
                borderWidth: 2,
                fill: true,
                tension: 0.4,
                pointRadius: 0,
                pointHoverRadius: 4
            }, {
                label: 'Available',
                data: [],
                borderColor: '#74b9ff',
                backgroundColor: 'rgba(116, 185, 255, 0.1)',
                borderWidth: 2,
                fill: true,
                tension: 0.4,
                pointRadius: 0,
                pointHoverRadius: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: false,
            plugins: {
                legend: {
                    display: true,
                    labels: { color: '#a0a0b0' }
                },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            return context.dataset.label + ': ' + formatBytes(context.raw);
                        }
                    }
                }
            },
            scales: {
                x: {
                    display: false
                },
                y: {
                    grid: {
                        color: 'rgba(255, 255, 255, 0.05)'
                    },
                    ticks: {
                        color: '#707080',
                        callback: function(value) {
                            return formatBytes(value, 0);
                        }
                    }
                }
            },
            interaction: {
                intersect: false,
                mode: 'index'
            }
        }
    });
}

// ==================== DOM UPDATES ====================

/**
 * Update connection status indicator
 */
function updateConnectionStatus(connected) {
    const indicator = document.getElementById('connectionStatus');
    const badge = document.querySelector('.update-badge');

    if (connected) {
        indicator.classList.add('connected');
        badge.classList.add('live');
        badge.textContent = 'Live';
    } else {
        indicator.classList.remove('connected');
        badge.classList.remove('live');
        badge.textContent = 'Offline';
    }
}

/**
 * Update CPU section
 */
function updateCpuSection(cpu) {
    // Overall CPU
    const overallEl = document.getElementById('cpuOverall');
    const overallBar = document.getElementById('cpuOverallBar');
    overallEl.textContent = cpu.usage.toFixed(1) + '%';
    overallBar.style.width = cpu.usage + '%';
    overallBar.style.background = getColorForPercentage(cpu.usage);

    // Frequency
    document.getElementById('cpuFrequency').textContent = cpu.frequency.toFixed(2) + ' GHz';

    // Load Average
    const loadText = cpu.loadAverage.map(l => l.toFixed(2)).join(' / ');
    document.getElementById('cpuLoad').textContent = loadText;

    // Per-core bars
    updateCoreBars(cpu.cores);

    // Update chart
    updateCpuChart(cpu.usage);
}

/**
 * Update per-core bars
 */
function updateCoreBars(cores) {
    const container = document.getElementById('coresContainer');

    // Create core bars if they don't exist
    if (container.children.length !== cores.length) {
        container.innerHTML = '';
        cores.forEach((_, index) => {
            const row = document.createElement('div');
            row.className = 'core-row';
            row.innerHTML = `
                <span class="core-label">Core ${index}</span>
                <div class="core-bar-container">
                    <div class="core-bar" id="coreBar${index}" style="width: 0%">
                        <span class="core-bar-text" id="coreText${index}">0%</span>
                    </div>
                </div>
            `;
            container.appendChild(row);
        });

        // Update cores count badge
        document.getElementById('cpuCoresCount').textContent = cores.length + ' cores';
    }

    // Update each core bar
    cores.forEach((usage, index) => {
        const bar = document.getElementById(`coreBar${index}`);
        const text = document.getElementById(`coreText${index}`);
        if (bar && text) {
            bar.style.width = usage + '%';
            bar.style.background = `linear-gradient(90deg, ${getColorForPercentage(usage)}, ${getColorForPercentage(usage * 0.8)})`;
            text.textContent = usage.toFixed(1) + '%';
        }
    });
}

/**
 * Update Memory section
 */
function updateMemorySection(memory) {
    const totalGB = memory.total;
    const usedGB = memory.used;
    const freeGB = memory.free;
    const availableGB = memory.available;

    // Update metric cards
    document.getElementById('memTotal').textContent = formatBytes(totalGB, 1) + ' total';
    document.getElementById('memUsed').textContent = formatBytes(usedGB, 1);
    document.getElementById('memFree').textContent = formatBytes(freeGB, 1);
    document.getElementById('memAvailable').textContent = formatBytes(availableGB, 1);

    // Progress bar
    const usedPct = totalGB > 0 ? (usedGB / totalGB * 100) : 0;
    const usedBar = document.getElementById('memUsedBar');
    usedBar.style.width = usedPct + '%';
    usedBar.style.background = getColorForPercentage(usedPct);

    // Breakdown
    document.getElementById('memActive').textContent = formatBytes(memory.active, 1);
    document.getElementById('memBuffers').textContent = formatBytes(memory.buffers, 1);
    document.getElementById('memCached').textContent = formatBytes(memory.cached, 1);

    // Swap
    document.getElementById('swapTotal').textContent = formatBytes(memory.swapTotal, 1);
    document.getElementById('swapUsed').textContent = formatBytes(memory.swapUsed, 1);
    document.getElementById('swapFree').textContent = formatBytes(memory.swapFree, 1);

    const swapUsedPct = memory.swapTotal > 0 ? (memory.swapUsed / memory.swapTotal * 100) : 0;
    const swapBar = document.getElementById('swapUsedBar');
    swapBar.style.width = swapUsedPct + '%';
    swapBar.style.background = getColorForPercentage(swapUsedPct);

    // Update chart
    updateMemoryChart(usedGB, availableGB);
}

/**
 * Update CPU chart with new data point
 */
function updateCpuChart(usage) {
    const now = new Date();
    const timeLabel = now.toTimeString().split(' ')[0];

    cpuHistory.labels.push(timeLabel);
    cpuHistory.overall.push(usage);

    // Keep only last MAX_HISTORY_POINTS
    if (cpuHistory.labels.length > MAX_HISTORY_POINTS) {
        cpuHistory.labels.shift();
        cpuHistory.overall.shift();
    }

    cpuChart.data.labels = cpuHistory.labels;
    cpuChart.data.datasets[0].data = cpuHistory.overall;
    cpuChart.update('none'); // 'none' mode for performance
}

/**
 * Update Memory chart with new data point
 */
function updateMemoryChart(used, available) {
    const now = new Date();
    const timeLabel = now.toTimeString().split(' ')[0];

    memoryHistory.labels.push(timeLabel);
    memoryHistory.used.push(used);
    memoryHistory.available.push(available);

    // Keep only last MAX_HISTORY_POINTS
    if (memoryHistory.labels.length > MAX_HISTORY_POINTS) {
        memoryHistory.labels.shift();
        memoryHistory.used.shift();
        memoryHistory.available.shift();
    }

    memoryChart.data.labels = memoryHistory.labels;
    memoryChart.data.datasets[0].data = memoryHistory.used;
    memoryChart.data.datasets[1].data = memoryHistory.available;
    memoryChart.update('none');
}

/**
 * Update timestamp display
 */
function updateTimestamp() {
    document.getElementById('lastUpdate').textContent = formatTime(Date.now());
}

// ==================== WEBSOCKET HANDLING ====================

/**
 * Connect to WebSocket server
 */
function connectWebSocket() {
    console.log('[WS] Connecting to', WS_URL);

    ws = new WebSocket(WS_URL);

    ws.onopen = function() {
        console.log('[WS] Connected');
        isConnected = true;
        reconnectAttempts = 0;
        updateConnectionStatus(true);
    };

    ws.onmessage = function(event) {
        try {
            const data = JSON.parse(event.data);
            handleMetricsUpdate(data);
        } catch (error) {
            console.error('[WS] Error parsing message:', error);
        }
    };

    ws.onclose = function() {
        console.log('[WS] Disconnected');
        isConnected = false;
        updateConnectionStatus(false);
        attemptReconnect();
    };

    ws.onerror = function(error) {
        console.error('[WS] Error:', error);
    };
}

/**
 * Handle incoming metrics data
 */
function handleMetricsUpdate(data) {
    if (data.cpu) {
        updateCpuSection(data.cpu);
    }
    if (data.memory) {
        updateMemorySection(data.memory);
    }
    updateTimestamp();
}

/**
 * Attempt to reconnect with exponential backoff
 */
function attemptReconnect() {
    if (reconnectAttempts >= maxReconnectAttempts) {
        console.log('[WS] Max reconnection attempts reached');
        return;
    }

    reconnectAttempts++;
    const delay = Math.min(1000 * Math.pow(2, reconnectAttempts), 30000);

    console.log(`[WS] Reconnecting in ${delay}ms (attempt ${reconnectAttempts}/${maxReconnectAttempts})`);

    setTimeout(() => {
        if (!isConnected) {
            connectWebSocket();
        }
    }, delay);
}

// ==================== INITIALIZATION ====================

/**
 * Initialize the application
 */
function init() {
    console.log('[App] Initializing System Monitor Dashboard');

    // Initialize charts
    initCpuChart();
    initMemoryChart();

    // Connect to WebSocket
    connectWebSocket();

    // Handle page visibility changes
    document.addEventListener('visibilitychange', () => {
        if (document.visibilityState === 'visible' && !isConnected) {
            console.log('[App] Page visible, reconnecting...');
            connectWebSocket();
        }
    });
}

// Start when DOM is ready
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
} else {
    init();
}
