/**
 * metrics.js
 * System metrics collection module using systeminformation
 * Provides normalized CPU and Memory data for the dashboard
 */

const si = require('systeminformation');

/**
 * Format bytes to human-readable string (GB, MB, etc.)
 */
function formatBytes(bytes, decimals = 2) {
    if (bytes === 0 || bytes === undefined || bytes === null) return '0 B';
    const k = 1024;
    const dm = decimals < 0 ? 0 : decimals;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i];
}

/**
 * Collect all CPU metrics
 * Returns: { usage, cores[], frequency, loadAverage }
 */
async function getCpuMetrics() {
    try {
        const [currentLoad, cpuSpeed] = await Promise.all([
            si.currentLoad(),
            si.cpuCurrentSpeed()
        ]);

        // Per-core usage percentages
        const cores = currentLoad.cpus.map(core => {
            const load = core.load !== undefined ? core.load : 0;
            return parseFloat(load.toFixed(1));
        });

        // Overall CPU usage - use currentLoad property (camelCase)
        const usage = currentLoad.currentLoad !== undefined 
            ? parseFloat(currentLoad.currentLoad.toFixed(1)) 
            : 0;

        // CPU frequency (average in GHz)
        const frequency = cpuSpeed.avg !== undefined 
            ? parseFloat(cpuSpeed.avg.toFixed(2)) 
            : 0;

        // Load average - use avgLoad from currentLoad if available
        let loadAverage = [0, 0, 0];
        if (currentLoad.avgLoad !== undefined) {
            const load = parseFloat(currentLoad.avgLoad.toFixed(2));
            loadAverage = [load, load, load];
        } else if (usage > 0) {
            loadAverage = [usage / 100, usage / 100, usage / 100];
        }

        return {
            usage,
            cores,
            frequency,
            loadAverage
        };
    } catch (error) {
        console.error('Error collecting CPU metrics:', error.message);
        return {
            usage: 0,
            cores: [],
            frequency: 0,
            loadAverage: [0, 0, 0]
        };
    }
}

/**
 * Collect all Memory metrics
 * Returns: { total, used, free, available, active, buffers, cached, swapTotal, swapUsed, swapFree }
 */
async function getMemoryMetrics() {
    try {
        const mem = await si.mem();

        return {
            total: mem.total || 0,
            used: mem.used || 0,
            free: mem.free || 0,
            available: mem.available || 0,
            active: mem.active || 0,
            buffers: mem.buffers || 0,
            cached: mem.cached || 0,
            swapTotal: mem.swaptotal || 0,
            swapUsed: mem.swapused || 0,
            swapFree: mem.swapfree || 0
        };
    } catch (error) {
        console.error('Error collecting memory metrics:', error.message);
        return {
            total: 0,
            used: 0,
            free: 0,
            available: 0,
            active: 0,
            buffers: 0,
            cached: 0,
            swapTotal: 0,
            swapUsed: 0,
            swapFree: 0
        };
    }
}

/**
 * Collect all system metrics in one call
 * Returns unified payload for WebSocket broadcast
 */
async function getAllMetrics() {
    const [cpu, memory] = await Promise.all([
        getCpuMetrics(),
        getMemoryMetrics()
    ]);

    return {
        timestamp: Date.now(),
        cpu,
        memory
    };
}

module.exports = {
    getCpuMetrics,
    getMemoryMetrics,
    getAllMetrics,
    formatBytes
};


