.table-card {
    padding: 0;
    overflow: hidden;
}

.table-toolbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 20px;
    border-bottom: 1px solid var(--border-color);
    flex-wrap: wrap;
    gap: 10px;
}

.table-info {
    font-size: 0.8rem;
    color: var(--text-muted);
}

.sort-controls {
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
}

.sort-btn {
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border: 1px solid var(--border-color);
    border-radius: 6px;
    padding: 6px 14px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: var(--transition);
    font-family: inherit;
}

.sort-btn:hover {
    background: var(--bg-card-hover);
    color: var(--text-primary);
}

.sort-btn.active {
    background: var(--accent-info);
    color: var(--bg-primary);
    border-color: var(--accent-info);
    font-weight: 600;
}

.table-wrapper {
    overflow-x: auto;
    max-height: 500px;
    overflow-y: auto;
}

.table-wrapper::-webkit-scrollbar {
    height: 6px;
    width: 6px;
}

.table-wrapper::-webkit-scrollbar-thumb {
    background: var(--border-color);
    border-radius: 3px;
}

.process-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.9rem;
}

.process-table thead {
    position: sticky;
    top: 0;
    z-index: 10;
}

.process-table th {
    background: var(--bg-secondary);
    color: var(--text-secondary);
    padding: 12px 16px;
    text-align: left;
    font-weight: 600;
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    border-bottom: 2px solid var(--border-color);
    cursor: pointer;
    user-select: none;
    transition: var(--transition);
    white-space: nowrap;
}

.process-table th:hover {
    color: var(--text-primary);
    background: var(--bg-card-hover);
}

.process-table th.sort-asc::after {
    content: ' ▲';
    color: var(--accent-info);
}

.process-table th.sort-desc::after {
    content: ' ▼';
    color: var(--accent-info);
}

.process-table td {
    padding: 10px 16px;
    border-bottom: 1px solid var(--border-color);
    color: var(--text-primary);
    font-family: 'Courier New', monospace;
    font-size: 0.85rem;
    white-space: nowrap;
}

.process-table tbody tr {
    transition: var(--transition);
}

.process-table tbody tr:hover {
    background: var(--bg-card-hover);
}

.process-table tbody tr:nth-child(even) {
    background: rgba(255, 255, 255, 0.02);
}

.process-table tbody tr:nth-child(even):hover {
    background: var(--bg-card-hover);
}

/* High usage highlighting */
.process-table tbody tr.high-cpu td:nth-child(3) {
    color: var(--danger);
    font-weight: 700;
}

.process-table tbody tr.high-mem td:nth-child(4) {
    color: var(--accent-memory);
    font-weight: 700;
}

.process-table tbody tr.high-usage {
    background: rgba(255, 107, 107, 0.08);
}

.process-table tbody tr.high-usage:hover {
    background: rgba(255, 107, 107, 0.15);
}

/* Process name cell */
.process-table td:nth-child(2) {
    font-family: inherit;
    font-weight: 500;
    max-width: 200px;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* Command cell */
.process-table td:nth-child(6) {
    max-width: 300px;
    overflow: hidden;
    text-overflow: ellipsis;
    color: var(--text-muted);
    font-size: 0.8rem;
}

/* PID cell */
.process-table td:nth-child(1) {
    color: var(--text-muted);
}

/* User cell */
.process-table td:nth-child(5) {
    color: var(--text-secondary);
    font-size: 0.8rem;
}

/* Responsive table */
@media (max-width: 768px) {
    .table-toolbar {
        flex-direction: column;
        align-items: flex-start;
    }

    .sort-controls {
        width: 100%;
    }

    .process-table {
        font-size: 0.8rem;
    }

    .process-table th,
    .process-table td {
        padding: 8px 10px;
    }

    .process-table td:nth-child(6) {
        max-width: 150px;
    }
}

@media (max-width: 480px) {
    .process-table th:nth-child(5),
    .process-table td:nth-child(5) {
        display: none;
    }

