// ==================== CONFIGURATION ====================
const WS_URL = `ws://${window.location.host}`;
const MAX_HISTORY_POINTS = 60; // 60 seconds of history
const UPDATE_INTERVAL = 1000;

// ==================== STATE ====================
let ws = null;
let reconnectAttempts = 0;
const maxReconnectAttempts = 10;
