    const sorted = [...currentProcesses];
    const col = processSortColumn;
    const dir = processSortDirection;

    sorted.sort((a, b) => {
        let valA = a[col] || 0;
        let valB = b[col] || 0;

        // String comparison for name, user, command
        if (col === 'name' || col === 'user' || col === 'command') {
            valA = (valA || '').toString().toLowerCase();
            valB = (valB || '').toString().toLowerCase();
            if (valA < valB) return dir === 'asc' ? -1 : 1;
            if (valA > valB) return dir === 'asc' ? 1 : -1;
            return 0;
        }

        // Numeric comparison
        return dir === 'asc' ? valA - valB : valB - valA;
    });

    return sorted;
}

