#< CLIXML
/**
 * server.js
 * Express HTTP server + WebSocket for real-time system metrics streaming
 */

const express = require('express');
const { createServer } = require('http');
const { WebSocketServer } = require('ws');
const path = require('path');
const { getAllMetrics } = require('./metrics');

const app = express();
const server = createServer(app);
const wss = new WebSocketServer({ server });

const PORT = process.env.PORT || 3000;
const UPDATE_INTERVAL = 1000; // 1 second

// Serve static files from public directory
app.use(express.static(path.join(__dirname, 'public')));

// Health check endpoint
app.get('/health', (req, res) => {
    res.json({ status: 'ok', uptime: process.uptime() });
});

// Root route serves the dashboard
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'index.html'));
});

// WebSocket connection handling
wss.on('connection', (ws, req) => {
    const clientIp = req.socket.remoteAddress;
    console.log(`[WS] Client connected from ${clientIp}. Total clients: ${wss.clients.size}`);

    // Send initial data immediately
    sendMetricsToClient(ws);

    ws.on('close', () => {
        console.log(`[WS] Client disconnected. Total clients: ${wss.clients.size}`);
    });

    ws.on('error', (error) => {
        console.error('[WS] Client error:', error.message);
    });
});

/**
 * Send metrics to a single WebSocket client
 */
async function sendMetricsToClient(ws) {
    try {
        if (ws.readyState === ws.OPEN) {
            const metrics = await getAllMetrics();
            ws.send(JSON.stringify(metrics));
        }
    } catch (error) {
        console.error('[WS] Error sending metrics to client:', error.message);
    }
}

/**
 * Broadcast metrics to all connected WebSocket clients
 */
async function broadcastMetrics() {
    try {
        const metrics = await getAllMetrics();
        const message = JSON.stringify(metrics);
        let sentCount = 0;

        wss.clients.forEach((client) => {
            if (client.readyState === client.OPEN) {
                client.send(message);
                sentCount++;
            }
        });

        if (sentCount > 0) {
            console.log(`[Metrics] Broadcasted to ${sentCount} client(s) at ${new Date().toISOString()}`);
        }
    } catch (error) {
        console.error('[Metrics] Error broadcasting:', error.message);
    }
}

// Start periodic metrics broadcasting
const broadcastInterval = setInterval(broadcastMetrics, UPDATE_INTERVAL);

// Graceful shutdown
process.on('SIGINT', () => {
    console.log('\n[Server] Shutting down gracefully...');
    clearInterval(broadcastInterval);
    wss.close(() => {
        console.log('[WS] WebSocket server closed');
        server.close(() => {
            console.log('[Server] HTTP server closed');
            process.exit(0);
        });
    });
});

// Start server
server.listen(PORT, () => {
    console.log('='.repeat(50));
    console.log('  CPU, Memory & Process Monitor');
    console.log('  Real-time System Dashboard');
    console.log('='.repeat(50));
    console.log(`  Server running at: http://localhost:${PORT}`);
    console.log(`  WebSocket endpoint: ws://localhost:${PORT}`);
    console.log(`  Update interval: ${UPDATE_INTERVAL}ms`);
    console.log('='.repeat(50));
    console.log('  Press Ctrl+C to stop\n');
});

